import { Component, OnInit } from '@angular/core';
import { DashboardService } from '../../../../core/services/dashboard.service';
import { CommonModule } from '@angular/common';
import { BaseChartDirective } from 'ng2-charts';
import { forkJoin, of } from 'rxjs';
import { catchError, finalize } from 'rxjs/operators';

@Component({
  selector: 'app-dashboard',
  imports: [CommonModule, BaseChartDirective],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css'
})
export class DashboardComponent implements OnInit{
 stats: any = {};
  loading = false;
  errorMsg = '';

  // Chart Data
  salaryChartData: any;
  attendanceChartData: any;

  constructor(private dashboardService: DashboardService) {}

  ngOnInit(): void {
    this.loadDashboard();
  }

  loadDashboard() {
    this.loading = true;
    this.errorMsg = '';

    forkJoin({
      stats: this.dashboardService.getStats().pipe(catchError(() => of(null))),
      salary: this.dashboardService.getMonthlySalary().pipe(catchError(() => of(null))),
      attendance: this.dashboardService.getAttendanceSummary().pipe(catchError(() => of(null))),
    })
      .pipe(
        finalize(() => {
          this.loading = false;
        }),
      )
      .subscribe((res) => {
        if (!res.stats || !res.salary || !res.attendance) {
          this.errorMsg = 'Failed to load dashboard data';
          return;
        }

        this.stats = res.stats.data;
        this.prepareSalaryChart(res.salary.data || []);
        this.prepareAttendanceChart(res.attendance.data || { present: 0, leave: 0 });
      });
  }

  /**
   * 📊 Salary Chart
   */
  prepareSalaryChart(data: any[]) {
    this.salaryChartData = {
      labels: data.map(d => d.month),
      datasets: [
        {
          data: data.map(d => d.totalSalary),
          label: 'Monthly Salary'
        }
      ]
    };
  }

  /**
   * 📊 Attendance Chart
   */
  prepareAttendanceChart(data: any) {
    this.attendanceChartData = {
      labels: ['Present', 'Leave'],
      datasets: [
        {
          data: [data.present, data.leave]
        }
      ]
    };
  }
}
